# Check if Domain Users or Authenticated Users can create DNS records
# This is the ADIDNS angle
python3 << 'PYEOF'
import ldap3
from ldap3 import Server, Connection, NTLM, BASE
from ldap3.protocol.microsoft import security_descriptor_control
from impacket.ldap.ldaptypes import SR_SECURITY_DESCRIPTOR
import uuid

server = Server('10.129.17.46', get_info=ldap3.ALL)
conn = Connection(server, user='garfield.htb\\j.arbuckle', password='Th1sD4mnC4t!@1978', authentication=NTLM, auto_bind=True)
controls = security_descriptor_control(sdflags=0x04)

# Check DNS zone ACL
dns_zones = [
    'DC=garfield.htb,CN=MicrosoftDNS,DC=DomainDnsZones,DC=garfield,DC=htb',
    'CN=MicrosoftDNS,DC=DomainDnsZones,DC=garfield,DC=htb',
]

for dn in dns_zones:
    conn.search(dn, '(objectClass=*)', search_scope=BASE,
                attributes=['nTSecurityDescriptor'], controls=controls)
    if not conn.entries:
        print(f"No access to {dn}")
        continue
    sd = SR_SECURITY_DESCRIPTOR()
    sd.fromString(conn.entries[0]['nTSecurityDescriptor'].raw_values[0])

    print(f"\n=== {dn} ===")
    for ace in sd['Dacl'].aces:
        ad = ace['Ace']
        sid = ad['Sid'].formatCanonical()
        mask = ad['Mask']['Mask']

        # Look for Authenticated Users (S-1-5-11), Domain Users, Everyone
        if sid in ['S-1-5-11', 'S-1-1-0'] or '-513' in sid:
            names = {'S-1-5-11': 'AuthUsers', 'S-1-1-0': 'Everyone'}
            sname = names.get(sid, 'DomainUsers' if '-513' in sid else sid)

            rights = []
            if mask & 0x10000000: rights.append('GA')
            if mask & 0x4: rights.append('CREATE_CHILD')
            if mask & 0x2: rights.append('DELETE_CHILD')
            if mask & 0x20: rights.append('WP')
            if mask & 0x10: rights.append('RP')
            if mask & 0x1: rights.append('LIST')
            if mask & 0x100: rights.append('EXT')

            if rights:
                print(f"  {sname}: mask=0x{mask:x} {','.join(rights)}")

conn.unbind()
PYEOF

